INSERT INTO review (booking_id, rating, title, comment, cleanliness_rating, service_rating, entertainment_rating, food_rating, is_verified, is_public, response_from_airline, response_date) VALUES
(1, 5, 'Excellent Business Class', 'Outstanding service and comfort on the New York to London route. Highly recommend!', 5, 5, 5, 5, TRUE, TRUE, 'Thank you for your wonderful feedback! We look forward to serving you again.', '2024-01-10 10:00:00'),
(2, 4, 'Good Economy Experience', 'Comfortable seat and friendly crew. Food could be better.', 4, 5, 4, 3, TRUE, TRUE, 'Glad you enjoyed the flight! We will work on improving our food options.', '2024-01-12 10:00:00'),
(3, 5, 'First Class at Its Best', 'Exceptional experience from check-in to landing. Worth every penny!', 5, 5, 5, 5, TRUE, TRUE, 'We are thrilled you enjoyed your First Class experience!', '2024-01-08 10:00:00'),
(4, 3, 'Average Premium Economy', 'Decent experience but legroom was a bit tight for premium economy.', 3, 4, 3, 3, TRUE, TRUE, 'Thank you for your feedback. We will review our premium economy configuration.', '2024-01-10 10:00:00'),
(5, 5, 'Perfect Business Journey', 'Smooth flight, great food, attentive crew. The Paris route is always excellent.', 5, 5, 4, 5, TRUE, TRUE, 'Thank you for your kind words!', '2024-01-12 10:00:00'),
(6, 4, 'Good Economy Flight', 'The gluten-free meal was actually quite good! Crew was helpful.', 4, 4, 3, 4, TRUE, TRUE, NULL, NULL),
(7, 3, 'Acceptable Budget Fare', 'Flight was on time but the cabin felt a bit dated.', 3, 3, 2, 3, TRUE, TRUE, 'We appreciate your feedback and are working on fleet upgrades.', '2024-01-16 10:00:00'),
(8, 5, 'Superb Business Class', 'Best business class experience I have had. Crew were incredibly professional.', 5, 5, 5, 5, TRUE, TRUE, 'Wonderful to hear! Thank you for choosing Aerox.', '2024-01-18 10:00:00'),
(9, 2, 'Very Delayed Flight', 'Flight was delayed 45 minutes and the explanation was poor. Disappointing.', 2, 2, 3, 2, TRUE, TRUE, 'We sincerely apologize for the delay. We are taking measures to prevent this.', '2024-01-22 10:00:00'),
(10, 4, 'Nice Premium Economy', 'Great value for money. Entertainment system was top notch.', 4, 4, 5, 4, TRUE, TRUE, NULL, NULL),
(11, 5, 'World Class Service', 'The Tokyo to Singapore connection was seamless. Crew went above and beyond.', 5, 5, 5, 5, TRUE, TRUE, 'We are delighted to hear this! See you on your next journey.', '2024-01-25 10:00:00'),
(12, 4, 'Smooth Economy Ride', 'Clean aircraft and comfortable seats. On-time arrival.', 4, 4, 4, 4, TRUE, TRUE, NULL, NULL),
(13, 3, 'Okay Domestic Flight', 'Short flight so not much to review. Crew was fine.', 3, 3, 2, 3, TRUE, TRUE, NULL, NULL),
(14, 5, 'Amazing First Class', 'The suite was incredible! Privacy, comfort and dining all world class.', 5, 5, 5, 5, TRUE, TRUE, 'Thank you! Your satisfaction is our priority.', '2024-01-28 10:00:00'),
(15, 4, 'Great Long-Haul Business', 'Lie-flat seats made the overnight flight very restful.', 4, 5, 4, 4, TRUE, TRUE, NULL, NULL),
(16, 3, 'Decent Economy', 'Nothing special but nothing bad. Got there safely and on time.', 3, 3, 3, 3, TRUE, TRUE, NULL, NULL),
(17, 5, 'Outstanding Business Class', 'Mumbai to London has never been more comfortable. Exemplary service.', 5, 5, 5, 5, TRUE, TRUE, 'We are so pleased you enjoyed your journey!', '2024-01-30 10:00:00'),
(18, 4, 'Pleasant Economy Journey', 'The new seats are much more comfortable. Good improvement!', 4, 4, 4, 3, TRUE, TRUE, 'Thank you for noticing our improvements!', '2024-02-02 10:00:00'),
(19, 4, 'Quick Regional Hop', 'Short flight was efficient and comfortable. Great staff.', 4, 5, 3, 3, TRUE, TRUE, NULL, NULL),
(20, 5, 'Fabulous Business Seat', 'Everything was perfect. Highly professional cabin crew.', 5, 5, 5, 5, TRUE, TRUE, 'Thank you! We look forward to your next flight.', '2024-02-06 10:00:00'),
(21, 3, 'Average Transatlantic', 'Food quality has declined. Entertainment was good though.', 3, 3, 4, 2, TRUE, TRUE, 'We hear your concerns about food quality. We are reviewing our catering.', '2024-02-08 10:00:00'),
(22, 4, 'Good Premium Economy', 'Extra legroom was worth the upgrade. Friendly attendants.', 4, 4, 4, 4, TRUE, TRUE, NULL, NULL),
(23, 4, 'Fine Domestic Service', 'Domestic flights have improved a lot. Clean planes and good crew.', 4, 4, 3, 3, TRUE, TRUE, NULL, NULL),
(24, 5, 'Fantastic First Class', 'The food was restaurant quality and the bed was incredibly comfortable.', 5, 5, 5, 5, TRUE, TRUE, 'Thank you for this wonderful review!', '2024-02-12 10:00:00'),
(25, 2, 'Disappointed with Business', 'Given medical assistance needed, the crew response was slow. Expected better.', 2, 2, 3, 3, TRUE, TRUE, 'We are very sorry to hear this. We have reviewed the incident with our crew team.', '2024-02-15 10:00:00'),
(26, 4, 'Good Short Haul', 'Quick and efficient. Exactly what you need for a short hop.', 4, 4, 3, 3, TRUE, TRUE, NULL, NULL),
(27, 3, 'Mediocre Economy', 'The seat was narrow and the food was just average.', 3, 3, 3, 2, TRUE, TRUE, 'Thank you for your honest feedback.', '2024-02-20 10:00:00'),
(28, 5, 'Best Business Flight Ever', 'Aerox business class is now my benchmark for all airlines.', 5, 5, 5, 5, TRUE, TRUE, 'This made our day! Thank you so much.', '2024-02-24 10:00:00'),
(29, 4, 'Pleasant Long Haul', 'Staff were attentive throughout the long flight. Comfortable seats.', 4, 4, 4, 4, TRUE, TRUE, NULL, NULL),
(30, 3, 'Okay Premium Economy', 'Delayed by 50 minutes which was frustrating but the in-flight experience was okay.', 3, 3, 4, 3, TRUE, TRUE, 'We apologize for the delay and appreciate your patience.', '2024-02-28 10:00:00'),
(31, 4, 'Solid Economy Transatlantic', 'Good price, decent legroom for economy. Entertainment was great.', 4, 4, 5, 3, TRUE, TRUE, NULL, NULL),
(32, 5, 'Excellent South American Route', 'Great service connecting São Paulo to Buenos Aires. Very smooth.', 5, 5, 4, 5, TRUE, TRUE, 'Thank you! Our South American routes are a point of pride.', '2024-02-14 10:00:00'),
(33, 3, 'Short But Unremarkable', 'Got there on time but nothing memorable about the experience.', 3, 3, 2, 3, FALSE, TRUE, NULL, NULL),
(34, 5, 'First Class Perfection', 'Buenos Aires to Madrid in absolute luxury. Could not fault a single thing.', 5, 5, 5, 5, TRUE, TRUE, 'We are delighted to have made your journey special!', '2024-02-18 10:00:00'),
(36, 4, 'Good Regional Flight', 'Short and sweet. Crew was excellent and very efficient.', 4, 5, 3, 4, TRUE, TRUE, NULL, NULL),
(37, 4, 'Comfortable Business Class', 'Good flat bed and attentive service. Would fly this route again.', 4, 4, 4, 4, TRUE, TRUE, NULL, NULL),
(38, 3, 'Average Long Haul Economy', 'Very long flight. Seat was not the most comfortable but crew were helpful.', 3, 4, 4, 3, TRUE, TRUE, NULL, NULL),
(39, 4, 'Good Connections', 'The Johannesburg to Nairobi route is very well managed. On time!', 4, 4, 3, 4, TRUE, TRUE, NULL, NULL),
(40, 5, 'Wonderful Premium Economy', 'Night flight to Dubai was very comfortable in premium economy.', 5, 5, 4, 4, TRUE, TRUE, 'Thank you for flying with us!', '2024-03-02 10:00:00'),
(41, 4, 'Nice Regional Connection', 'Bangkok to Singapore is a great short haul route. Clean and efficient.', 4, 4, 3, 4, TRUE, TRUE, NULL, NULL),
(42, 5, 'Amazing Short Hop', 'Even on a 1-hour flight the service was impeccable!', 5, 5, 3, 4, TRUE, TRUE, 'We aim for excellence even on short routes!', '2024-03-08 10:00:00'),
(43, 3, 'Okay Business Class', 'Business class was a bit dated on this aircraft. Service made up for it.', 3, 5, 3, 4, TRUE, TRUE, 'We appreciate your feedback on the cabin. Updates are coming soon.', '2024-03-12 10:00:00'),
(44, 4, 'Good Economy Trip', 'Surprisingly good economy class. Staff were wonderful with the infant.', 4, 5, 4, 3, TRUE, TRUE, 'Thank you for trusting us with your family travel!', '2024-03-15 10:00:00'),
(46, 4, 'Efficient Short Flight', 'Perfect for a quick hop between cities. No complaints.', 4, 4, 3, 3, TRUE, TRUE, NULL, NULL),
(47, 5, 'Outstanding Business Class', 'Hong Kong to Doha overnight in business class was superb. Slept the whole way!', 5, 5, 5, 5, TRUE, TRUE, 'We love to hear this! Sweet dreams at 35,000 feet!', '2024-03-25 10:00:00'),
(48, 1, 'Repeat Flyer Always Satisfied', 'Tokyo route is consistently excellent. I fly this monthly.', 5, 5, 4, 5, TRUE, FALSE, NULL, NULL),
(49, 4, 'Great Overnight Flight', 'The lie-flat bed is superb. Arrived in London refreshed.', 5, 4, 4, 4, TRUE, TRUE, NULL, NULL),
(50, 5, 'Consistently Great', 'This is my third time on this route. Always high quality.', 5, 5, 5, 5, TRUE, TRUE, 'Thank you for your loyalty to Aerox!', '2024-02-05 10:00:00');
